#!/usr/bin/env python3
"""
OpenClaw session index cleanup
Options:
  --agent <name>          Agent to clean (default: coding-agent)
  --keep-key <key>        Session key to protect from removal
  --prune <type>          Prune type: cron-base, cron-all, orphaned, duplicates
  --older-than-hours <N>  Only prune entries older than N hours
  --apply                Actually write changes (default: dry-run)
"""
import json, os, sys
from datetime import datetime, timezone

def ts_to_dt(ts_ms):
    return datetime.fromtimestamp(ts_ms / 1000, tz=timezone.utc)

def is_cron_base(e):
    label = e.get('label', '')
    return label.startswith('Cron:') or 'cron:' in label.lower()

def main():
    agent = None
    keep_keys = []
    prune_type = None
    older_than_hours = None
    apply = False

    i = 1
    while i < len(sys.argv):
        if sys.argv[i] == '--agent' and i+1 < len(sys.argv):
            agent = sys.argv[i+1]; i += 2
        elif sys.argv[i] == '--keep-key' and i+1 < len(sys.argv):
            keep_keys.append(sys.argv[i+1]); i += 2
        elif sys.argv[i] == '--prune' and i+1 < len(sys.argv):
            prune_type = sys.argv[i+1]; i += 2
        elif sys.argv[i] == '--older-than-hours' and i+1 < len(sys.argv):
            older_than_hours = int(sys.argv[i+1]); i += 2
        elif sys.argv[i] == '--apply':
            apply = True; i += 1
        else:
            i += 1

    agent = agent or 'coding-agent'
    store_path = f'/Users/ling/.openclaw/agents/{agent}/sessions/sessions.json'
    if not os.path.exists(store_path):
        print(f'{agent}: store not found')
        return

    with open(store_path) as f:
        raw = f.read()
    try:
        data = json.loads(raw)
    except json.JSONDecodeError:
        print(f'{agent}: failed to parse JSON')
        return

    # Normalize to list
    if isinstance(data, dict):
        entries = list(data.values())
    elif isinstance(data, list):
        entries = data
    else:
        print(f'{agent}: unknown format')
        return

    before = len(entries)
    seen_ids = {}
    result = []
    removed = 0
    now_ms = datetime.now(timezone.utc).timestamp() * 1000

    for e in entries:
        sid = e.get('sessionId', '')
        key = ***'key', sid)
        label = e.get('label', '')
        updated = e.get('updatedAt', 0)

        # Always keep explicitly requested keys
        if key in keep_keys:
            result.append(e)
            seen_ids[sid] = e
            continue

        # Prune logic
        if prune_type:
            if prune_type == 'orphaned':
                sf = e.get('sessionFile', '')
                if sf and not os.path.exists(sf):
                    removed += 1
                    continue
            elif prune_type in ('cron-base', 'cron-all'):
                is_cron = is_cron_base(e)
                if prune_type == 'cron-base':
                    # Only remove cron entries, not other types
                    if is_cron:
                        if older_than_hours:
                            age_hours = (now_ms - updated) / 3600000
                            if age_hours >= older_than_hours:
                                removed += 1
                                continue
                        else:
                            removed += 1
                            continue
                elif prune_type == 'cron-all':
                    if is_cron:
                        removed += 1
                        continue

        # Deduplicate by sessionId (keep most recent)
        if sid in seen_ids:
            prev = seen_ids[sid]
            prev_updated = prev.get('updatedAt', 0)
            curr_updated = updated
            if curr_updated > prev_updated:
                result.remove(prev)
                result.append(e)
                seen_ids[sid] = e
            else:
                removed += 1
            continue

        # Check missing sessionFile (orphaned)
        sf = e.get('sessionFile', '')
        if sf and not os.path.exists(sf):
            removed += 1
            continue

        seen_ids[sid] = e
        result.append(e)

    after = len(result)

    print(f'{agent}: {before} -> {after} (removed {removed})')

    if apply:
        # Reconstruct as dict keyed by sessionId
        if isinstance(data, dict):
            new_data = {e.get('sessionId', str(i)): e for i, e in enumerate(result)}
        else:
            new_data = result
        with open(store_path, 'w') as f:
            json.dump(new_data, f, indent=2)
        print(f'{agent}: written {after} entries')

if __name__ == '__main__':
    main()
